---@class LFightAniActor
local LFightAniActor = classX("LFightAniActor",nil)

---@param battleViewUnit  LBattleViewUnit
function LFightAniActor:ctor(battleViewUnit)
    ---@type LBattleViewUnit
    self._battleViewUnit = battleViewUnit

    self._bWaitEnd = false

    self._ani = nil

    self._isFreeze = false
    self._needReset = false
    self._resetExecute = false
    self._freezeExecuted = true

    self._endTime = 0

    --- 延迟检查时间
    self._delayCheckTime = nil
end

function LFightAniActor:PlayAni(ani,loop,aniTime,mixTime)
    local curTime = self._battleViewUnit:GetTime()
    self._ani = ani
    aniTime = aniTime or 0
    self._needReset = false
    self._resetExecute = true
    if aniTime > 0 then
        self._endTime = aniTime + curTime
        self._needReset = true
        self._resetExecute = false
    end
    self._battleViewUnit:PlayAnimationInfoEx_Actor(ani,loop,false,mixTime,1)

    if not self._needReset then
        self._delayCheckTime = curTime + 0.2
    else
        self._delayCheckTime = nil
    end
end

function LFightAniActor:OnUpdate(time, deltaTime)
    self:UpdateFreeze()
    self:UpdateAni(time)
    self:CheckUpdate(time)
end

function LFightAniActor:UpdateAni(time)
    if self._resetExecute then return end
    if time < self._endTime then return end
    self._resetExecute = true
    self:ResetAni()
end

function LFightAniActor:ResetAni()
    self:UpdateAnimationTimeScale()
    if not self._isFreeze and self._needReset then
        self._battleViewUnit:PlayIdle()
    end
end

function LFightAniActor:UpdateAnimationTimeScale()
    local timeScale = self._isFreeze and 0 or 1
    self._battleViewUnit:SetAnimationTimeScale_actor(timeScale)
end

function LFightAniActor:SetFreeze(isFreeze)
    self._isFreeze = isFreeze
    self._freezeExecuted = false
end

function LFightAniActor:GetAniName()
    return self._ani
end

function LFightAniActor:UpdateFreeze()
    if self._freezeExecuted then return end
    self._freezeExecuted = true
    self:ResetAni()
end

function LFightAniActor:CheckUpdate(time)
    if not self._delayCheckTime then return end
    if self._delayCheckTime < time then return end
    self._delayCheckTime = nil
    self:UpdateAnimationTimeScale()
end

function LFightAniActor:Dispose()
    if self._isDisposed then return end
    table.dispose(self)
    self._isDisposed = true
end

return LFightAniActor